import { Link, useNavigate, useLocation } from "react-router-dom";
import { useState } from "react";
import { Menu, X, Search, Bell, Home, FileText, CheckCircle, Shield } from "lucide-react";

export default function Navbar() {

  const navigate = useNavigate();
  const location = useLocation();
  const pathname = location.pathname || "/";

  const accessToken = localStorage.getItem("accessToken");
  const storedUser = localStorage.getItem("user");
  const user = storedUser ? JSON.parse(storedUser) : null;

  const isAuthPage =
    pathname === "/login" || pathname === "/register";

  const isLoggedIn = Boolean(accessToken) && !isAuthPage;
  const isAdmin = user?.role === "admin";

  const [open, setOpen] = useState(false);
  const [search, setSearch] = useState("");

  const logout = () => {

    localStorage.removeItem("accessToken");
    localStorage.removeItem("refreshToken");
    localStorage.removeItem("user");

    setOpen(false);

    navigate("/login", { replace: true });

  };

  const handleSearch = (e) => {

    e.preventDefault();

    if (!search.trim()) return;

    navigate(`/dashboard?search=${search}`);

    setSearch("");

  };

  return (

    <nav className="bg-white/90 backdrop-blur-md shadow-md sticky top-0 z-50">

      <div className="max-w-7xl mx-auto px-5 py-3 flex items-center justify-between">

        {/* LOGO */}

        <Link
          to={isLoggedIn ? "/dashboard" : "/login"}
          className="text-2xl font-extrabold tracking-wide flex items-center gap-1"
        >
          <span className="text-blue-600">we</span>
          <span className="text-gray-900">FOUND</span>
          <span className="text-green-600">it</span>
        </Link>


        {/* SEARCH BAR */}

        {isLoggedIn && (

          <form
            onSubmit={handleSearch}
            className="hidden md:flex items-center bg-gray-100 rounded-lg px-3 py-1.5 w-80"
          >

            <Search size={18} className="text-gray-500 mr-2" />

            <input
              type="text"
              placeholder="Search items..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="bg-transparent outline-none w-full text-sm"
            />

          </form>

        )}


        {/* DESKTOP MENU */}

        <div className="hidden md:flex items-center gap-6">

          <NavItem
            to="/dashboard"
            active={pathname === "/dashboard"}
            icon={<Home size={18} />}
          >
            Dashboard
          </NavItem>

          <NavItem
            to="/my-posts"
            active={pathname === "/my-posts"}
            icon={<FileText size={18} />}
          >
            My Posts
          </NavItem>

          <NavItem
            to="/returned"
            active={pathname === "/returned"}
            icon={<CheckCircle size={18} />}
          >
            Returned
          </NavItem>

          {isAdmin && (

            <NavItem
              to="/admin"
              active={pathname === "/admin"}
              icon={<Shield size={18} />}
            >
              Admin
            </NavItem>

          )}

          <NavItem
            to="/about"
            active={pathname === "/about"}
          >
            About
          </NavItem>


          {/* NOTIFICATION ICON */}

          <button className="relative hover:scale-105 transition">

            <Bell size={20} className="text-gray-600" />

            <span className="absolute -top-1 -right-1 bg-red-500 text-white text-xs w-4 h-4 flex items-center justify-center rounded-full">
              0
            </span>

          </button>


          {/* USER INFO */}

          {isLoggedIn && (

            <div className="flex items-center gap-3 ml-2">

              <span className="text-sm font-semibold text-gray-700">
                {user?.name || "User"}
              </span>

              {isAdmin && (
                <span className="bg-purple-100 text-purple-700 text-xs px-2 py-0.5 rounded-full font-bold">
                  ADMIN
                </span>
              )}

              <button
                onClick={logout}
                className="px-4 py-1.5 rounded-lg bg-red-500 text-white hover:bg-red-600 transition shadow-sm"
              >
                Logout
              </button>

            </div>

          )}

        </div>


        {/* MOBILE BUTTON */}

        <button
          onClick={() => setOpen(!open)}
          className="md:hidden"
        >

          {open
            ? <X size={26} />
            : <Menu size={26} />
          }

        </button>

      </div>


      {/* MOBILE MENU */}

      {open && (

        <div className="md:hidden border-t bg-white">

          <MobileLink to="/dashboard" setOpen={setOpen}>
            Dashboard
          </MobileLink>

          <MobileLink to="/my-posts" setOpen={setOpen}>
            My Posts
          </MobileLink>

          <MobileLink to="/returned" setOpen={setOpen}>
            Returned
          </MobileLink>

          {isAdmin && (
            <MobileLink to="/admin" setOpen={setOpen}>
              Admin
            </MobileLink>
          )}

          <MobileLink to="/about" setOpen={setOpen}>
            About
          </MobileLink>

          {isLoggedIn && (
            <button
              onClick={logout}
              className="block w-full text-left px-5 py-3 text-red-600 hover:bg-red-50"
            >
              Logout
            </button>
          )}

        </div>

      )}

    </nav>

  );

}


/* DESKTOP NAV ITEM */

function NavItem({ to, children, active, icon }) {

  return (

    <Link
      to={to}
      className={`flex items-center gap-1 font-medium transition
      ${active ? "text-blue-600" : "text-gray-700 hover:text-blue-600"}`}
    >

      {icon}

      {children}

    </Link>

  );

}


/* MOBILE LINK */

function MobileLink({ to, children, setOpen }) {

  return (

    <Link
      to={to}
      onClick={() => setOpen(false)}
      className="block px-5 py-3 text-gray-700 hover:bg-gray-100"
    >

      {children}

    </Link>

  );

}
